import React from "react";

const Home = () => {
  return <div>

    <div
      className="hero-container"
      style={{ backgroundImage: `url('/images/h1.png')` }}
    >
      <div className="hero-overlay">
        <h1>Lost Something? We'll Help You Find It.</h1>
        <h2>Found Something? Make Someone’s Day.</h2>
        <br />
        <div className="search-box">
          <input type="text" placeholder="Key in Nepal" />
          <select>
            <option>Nepal</option>
            <option>India</option>
          </select>
          <button>🔍</button>
        </div>
      </div>
    </div>

    <div className="body-container">
      <h1>Lost It? Found It? Share It Here.</h1>
      <p>Here, We help people unite them with their valuable lost item.</p>
        <br />
      <button>I've Found item</button>
      <button>I've Lost item</button>
    </div>

    </div>
